// G1: reconstruct failure context from the Error Trigger summary + the fetched runData.
// The Error Trigger payload has NO runData, so correlation_id / tenant_id / the original
// trigger payload can only come from the execution we fetched via the n8n API.
const et = $('Error Trigger').first().json || {};
const fetched = $('Fetch Execution').first().json || {};

const exec = et.execution || {};
const wf = et.workflow || {};
const err = exec.error || {};

const workflow_name = wf.name || 'unknown';
const workflow_id = wf.id || null;
const failed_node = exec.lastNodeExecuted || null;
const execution_id = exec.id || null;
const error_name = err.name || null;
const error_message = err.message || (failed_node ? ('Execution failed at ' + failed_node) : 'Unknown error');
const error_stack = err.stack || '';

// runData is absent if the fetch failed (continueRegularOutput) — degrade to nulls.
const runData = (fetched.data && fetched.data.resultData && fetched.data.resultData.runData) || {};

let correlation_id = null;
let tenant_id = null;
let trigger_payload = {};

for (const nodeName of Object.keys(runData)) {
  const runs = runData[nodeName] || [];
  for (const run of runs) {
    const branches = (run && run.data && run.data.main) || [];
    for (const branch of branches) {
      for (const item of (branch || [])) {
        const j = (item && item.json) || {};
        if (!correlation_id && j.correlation_id) correlation_id = j.correlation_id;
        if (!tenant_id && j.tenant_id) tenant_id = j.tenant_id;
        // First inbound body wins — that's the original event to replay (Contract B).
        if (Object.keys(trigger_payload).length === 0 && j.body && typeof j.body === 'object') {
          trigger_payload = j.body;
        }
      }
    }
  }
}

// dead_letter_queue.correlation_id is uuid (nullable). Drop anything non-uuid.
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (correlation_id && !uuidRe.test(String(correlation_id))) correlation_id = null;
if (tenant_id && !uuidRe.test(String(tenant_id))) tenant_id = null;

return [{ json: {
  workflow_name,
  workflow_id,
  failed_node,
  execution_id,
  error_name,
  error_message: String(error_message).slice(0, 500),
  error_stack: String(error_stack).slice(0, 1000),
  correlation_id,
  tenant_id,
  trigger_payload,
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, ''),
  telegram_token: $env.TELEGRAM_BOT_TOKEN || '',
  telegram_chat: $env.TELEGRAM_CHAT_ID || ''
} }];

// Classify for replay-safety. poison = non-retryable (bad data / logic / auth) ->
// parked as manual. transient = retryable (network / 5xx / rate-limit). Default transient
// (safe: a transient row is replayable; a mislabeled poison just wastes one replay).
const c = $('Extract Context').first().json;
const hay = ((c.error_message || '') + ' ' + (c.error_name || '')).toLowerCase();

const poison = ['syntaxerror','typeerror','unexpected token','missing tenant','cannot read prop','is not valid json',' 400',' 401',' 403',' 422','validation','malformed'];
const transient = ['etimedout','econnreset','eai_again','enotfound','timeout',' 429',' 500',' 502',' 503',' 504','stripe 5','socket hang up'];

let error_class = 'transient';
if (poison.some(s => hay.includes(s))) error_class = 'poison';
else if (transient.some(s => hay.includes(s))) error_class = 'transient';

return [{ json: Object.assign({}, c, { error_class }) }];

