// Non-throwing alert. G1 is the ONE workflow that must never itself error, so the
// Telegram call is a guarded HTTP call (not the telegram node, which throws on a
// missing token). Missing token / outage is swallowed and just reported in output.
const ctx = $('Classify Error').first().json;
const rpc = $('Upsert DLQ Row').first().json;

// bump_dlq returns TABLE -> PostgREST gives an array [{id,attempts,status}]. Empty/{} if the insert node failed.
const row = Array.isArray(rpc) ? (rpc[0] || {}) : (rpc || {});
const dlq_id = row.id || 'n/a';
const attempts = (row.attempts != null) ? row.attempts : '?';
const status = row.status || 'unknown';

const text = [
  '\ud83d\udea8 *FlowOps failure*',
  'Workflow: ' + (ctx.workflow_name || 'unknown'),
  'Node: ' + (ctx.failed_node || '\u2014'),
  'Class: ' + (ctx.error_class || '?') + ' \u00b7 attempts: ' + attempts + ' \u00b7 ' + status,
  'DLQ: `' + dlq_id + '`',
  'Correlation: `' + (ctx.correlation_id || '\u2014') + '`',
  '',
  String(ctx.error_message || '').slice(0, 200)
].join('\n');

let alert_delivered = false;
let notice = null;
const token = ctx.telegram_token;
const chat = ctx.telegram_chat;

if (token && chat) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + token + '/sendMessage',
      body: { chat_id: chat, text: text, parse_mode: 'Markdown' },
      json: true
    });
    alert_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}

return [{ json: { dlq_id, attempts, status, error_class: ctx.error_class, correlation_id: ctx.correlation_id, alert_delivered, notice } }];
